#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#define MAX_RECTANGLES 200000

// Structure to represent a rectangle
typedef struct {
    int li, bi, ri, ui;
} Rectangle;

// Comparison function for sorting rectangles
int compareRectangles(const void *a, const void *b) {
    Rectangle *r1 = (Rectangle *)a;
    Rectangle *r2 = (Rectangle *)b;
    if (r1->li < r2->li) return -1;
    else if (r1->li > r2->li) return 1;
    else {
        if (r1->bi < r2->bi) return -1;
        else if (r1->bi > r2->bi) return 1;
        else {
            if (r1->ri < r2->ri) return -1;
            else if (r1->ri > r2->ri) return 1;
            else {
                if (r1->ui < r2->ui) return -1;
                else if (r1->ui > r2->ui) return 1;
                else return 0;
            }
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        Rectangle rectangles[n];
        for (int i = 0; i < n; i++) {
            scanf("%d %d %d %d", &rectangles[i].li, &rectangles[i].bi, &rectangles[i].ri, &rectangles[i].ui);
        }
        qsort(rectangles, n, sizeof(Rectangle), compareRectangles);
        long long minTimeUnits = 0;
        for (int i = 1; i < n; i++) {
            if (rectangles[i].li < rectangles[i-1].ri && rectangles[i].bi < rectangles[i-1].ui) {
                minTimeUnits += rectangles[i-1].ri - rectangles[i].li;
                minTimeUnits += rectangles[i-1].ui - rectangles[i].bi;
            } else {
                printf("-1\n");
                break;
            }
        }
        if (i == n) printf("%lld\n", minTimeUnits);
    }
    return 0;
}

