import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Rectangle implements Comparable<Rectangle> {
        int li, bi, ri, ui;
        Rectangle(int li, int bi, int ri, int ui) {
            this.li = li;
            this.bi = bi;
            this.ri = ri;
            this.ui = ui;
        }
        @Override
        public int compareTo(Rectangle o) {
            if (li < o.li) return -1;
            else if (li > o.li) return 1;
            else {
                if (bi < o.bi) return -1;
                else if (bi > o.bi) return 1;
                else {
                    if (ri < o.ri) return -1;
                    else if (ri > o.ri) return 1;
                    else {
                        if (ui < o.ui) return -1;
                        else if (ui > o.ui) return 1;
                        else return 0;
                    }
                }
            }
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            Rectangle[] rectangles = new Rectangle[n];
            for (int i = 0; i < n; i++) {
                rectangles[i] = new Rectangle(scanner.nextInt(), scanner.nextInt(), scanner.nextInt(), scanner.nextInt());
            }
            Arrays.sort(rectangles);
            long minTimeUnits = 0;
            for (int i = 1; i < n; i++) {
                if (rectangles[i].li < rectangles[i-1].ri && rectangles[i].bi < rectangles[i-1].ui) {
                    minTimeUnits += rectangles[i-1].ri - rectangles[i].li;
                    minTimeUnits += rectangles[i-1].ui - rectangles[i].bi;
                } else {
                    System.out.println(-1);
                    break;
                }
            }
            if (i == n) System.out.println(minTimeUnits);
        }
    }
}

